```class Solution {
    public int numSub(String s) {
        int MOD = 1000000007;
        int res = 0, count = 0;
        for (char c : s.toCharArray()) {
            if (c == '1') {
                count++;
            } else {
                res += (count * (count + 1)) / 2;
                count = 0;
            }
        }
        res += (count * (count + 1)) / 2;
        return (int) (res % MOD);
    }
}```
